      out.write("<script>\n");
      out.write("\n");
      out.write("    $(\"#inp-query\").bind(\"keyup\",function () {\n");
      out.write("        var width = document.getElementById(\"inp-query\").offsetWidth+\"px\";\n");
      out.write("        $(\"#search-suggest\").show().css({\n");
      out.write("            width:width\n");
      out.write("        });\n");
      out.write("\n");
      out.write("        //在搜索框输入数据，提示相关搜索信息\n");
      out.write("        var searchText=$(\"#inp-query\").val();\n");
      out.write("\n");
      out.write("        $(\"#search-result\").children().remove();\n");
      out.write("        $.post(\"/search\",{\"search_text\":searchText},function (data) {\n");
      out.write("            if (data.status == 200) {\n");
      out.write("                if(data.data.length!=0) {\n");
      out.write("                    $.each(data.data, function (i, item) {\n");
      out.write("                        var headHtml = $(\"#movie-tmpl\").html();\n");
      out.write("                        var formatDate = item.showyear;\n");
      out.write("                        headHtml = headHtml.replace(/{id}/g, item.movieid);\n");
      out.write("                        headHtml = headHtml.replace(/{cover}/g, item.picture);\n");
      out.write("                        headHtml = headHtml.replace(/{moviename}/g, item.moviename);\n");
      out.write("                        headHtml = headHtml.replace(/{showyear}/g, dateFormat(formatDate,'yyyy-MM-dd'));\n");
      out.write("                        headHtml = headHtml.replace(/{director}/g, item.director);\n");
      out.write("                        headHtml = headHtml.replace(/{averating}/s, item.averating);\n");
      out.write("                        $(\"#search-result\").append(headHtml);\n");
      out.write("                    })\n");
      out.write("                }\n");
      out.write("                else\n");
      out.write("                {\n");
      out.write("//                $(\"#search-result\").html(\"查无此片\");\n");
      out.write("                    alert(\"差不到此电影哦~\")\n");
      out.write("                }\n");
      out.write("            }\n");
      out.write("            else {\n");
      out.write("//            alert(\"加载更多图片资源错误\");\n");
      out.write("            }\n");
      out.write("\n");
      out.write("        })\n");
      out.write("    });\n");
      out.write("\n");
      out.write("\n");
      out.write("</script>\n");
      out.write("\n");
      out.write("\n");
      out.write("<script type=\"text/tmpl\"  id=\"movie-tmpl\">\n");
      out.write(" <li id=\"searchResult\">\n");
      out.write("   <div>\n");
      out.write("      <a value=\"{id}\" style=\"text-decoration:none\" onclick='javascript:$.post(\"/Customer/Description\",{id:$(this).attr(\"value\")}, function (data) {\n");
      out.write("            if (data==\"success\") {\n");
      out.write("                location.href = \"/MovieDescription\"\n");
      out.write("            } else {\n");
      out.write("            }\n");
      out.write("        })'>\n");
      out.write("         <div style=\"float:left\">\n");
      out.write("            <img src=\"{cover}\" style=\"width:80px;height:120px\">\n");
      out.write("         </div>\n");
      out.write("         <div  style=\"padding:12px\">\n");
      out.write("            <span>&nbsp;&nbsp;&nbsp;&nbsp;电影名称：{moviename}</span>\n");
      out.write("            <br>\n");
      out.write("            <span>&nbsp;&nbsp;&nbsp;&nbsp;上映时间:{showyear}</span>\n");
      out.write("            <br>\n");
      out.write("            <span>&nbsp;&nbsp;&nbsp;&nbsp;导演：{director}</span>\n");
      out.write("             <br>\n");
      out.write("            <span>&nbsp;&nbsp;&nbsp;&nbsp;评分：{averating}</span>\n");
      out.write("         </div>\n");
      out.write("       </a>\n");
      out.write("   </div>\n");
      out.write(" </li>\n");
      out.write("\n");
      out.write("</script>\n");
      out.write("\n");
      out.write("<!-- string cst时间转date-->\n");
      out.write("<script>\n");
      out.write("    function dateFormat(date, format) {\n");
      out.write("        date = new Date(date);\n");
      out.write("        var o = {\n");
      out.write("            'M+' : date.getMonth() + 1, //month\n");
      out.write("            'd+' : date.getDate(), //day\n");
      out.write("        };\n");
      out.write("        if (/(y+)/.test(format))\n");
      out.write("            format = format.replace(RegExp.$1, (date.getFullYear() + '').substr(4 - RegExp.$1.length));\n");
      out.write("\n");
      out.write("        for (var k in o)\n");
      out.write("            if (new RegExp('(' + k + ')').test(format))\n");
      out.write("                format = format.replace(RegExp.$1, RegExp.$1.length == 1 ? o[k] : ('00' + o[k]).substr(('' + o[k]).length));\n");
      out.write("        return format;\n");
      out.write("    }\n");
      out.write("</script>\n");
      out.write("</body>\n");
      out.write("</html>\n");
